const { setActive } = useOrganizationList();
const [collapsedGroups, setCollapsedGroups] = useState<Set<string>>(
  new Set(),
);

const toggleGroup = (group: string) => {
  setCollapsedGroups((prev) => {
    const next = new Set(prev);
    if (next.has(group)) {
      next.delete(group);
    } else {
      next.add(group);
    }
    return next;
  });
};

