190						data-sidebar="sidebar"
191						data-slot="sidebar"
192						data-mobile="true"
193						className="bg-sidebar text-sidebar-foreground w-(--sidebar-width) p-0 [&>button]:hidden"
194						style={
195							{
196								"--sidebar-width": SIDEBAR_WIDTH_MOBILE,
197							} as React.CSSProperties
198						}
199						side={side}
200					>
201						<SheetHeader className="sr-only">
202							<SheetTitle>Sidebar</SheetTitle>
203							<SheetDescription>Displays the mobile sidebar.</SheetDescription>
204						</SheetHeader>
205						<div className="flex h-full w-full flex-col">{children}</div>
206					</SheetContent>
207				</Sheet>
208			);
209		}
210	
211		return (
