229							: "group-data-[collapsible=icon]:w-(--sidebar-width-icon)",
230						variant === "floating" || variant === "inset"
231							? "group-data-[collapsible=header-only]:w-[calc(var(--sidebar-width-header-only)+(--spacing(4)))]"
232							: "group-data-[collapsible=header-only]:w-(--sidebar-width-header-only)",
233					)}
