245							: "group-data-[collapsible=icon]:w-(--sidebar-width-icon) group-data-[side=left]:border-r group-data-[side=right]:border-l",
246						variant === "floating" || variant === "inset"
247							? "group-data-[collapsible=header-only]:w-[calc(var(--sidebar-width-header-only)+(--spacing(4))+2px)]"
248							: "group-data-[collapsible=header-only]:w-(--sidebar-width-header-only) group-data-[side=left]:border-r group-data-[side=right]:border-l",
249						className,
250					)}
251					{...props}
252				>
253					<div
254						data-sidebar="sidebar"
255						data-slot="sidebar-inner"
256						className="bg-sidebar group-data-[variant=floating]:border-sidebar-border flex h-full w-full flex-col group-data-[variant=floating]:rounded-lg group-data-[variant=floating]:border group-data-[variant=floating]:shadow-sm"
