	return (
		<div
			data-slot="sidebar-group"
			data-sidebar="group"
			className={cn("relative flex w-full min-w-0 flex-col p-2", className)}
			{...props}
		>
			{collapsible && label ? (
				<AccordionPrimitive.Root
					type="multiple"
					defaultValue={defaultOpen ? [label] : []}
				>
					<AccordionPrimitive.Item value={label}>
						<SidebarMenu>
							<SidebarMenuItem>
								<SidebarMenuButton
									asChild
									size="sm"
									className="rounded-xl text-muted-foreground [&>svg]:size-3.5 [&[data-state=closed]>svg]:rotate-[-90deg] [&>svg]:transition-transform [&>svg]:duration-200"
								>
