	defaultOpen?: boolean;
}) {
	return (
		<div
			data-slot="sidebar-group"
			data-sidebar="group"
			className={cn("relative flex w-full min-w-0 flex-col p-2", className)}
			{...props}
		>
			{collapsible && label ? (
				<AccordionPrimitive.Root
					type="multiple"
					defaultValue={defaultOpen ? [label] : []}
				>
					<AccordionPrimitive.Item value={label}>
						<SidebarMenu>
							<SidebarMenuItem>
								<SidebarMenuButton
									asChild
									size="sm"
									className="rounded-xl text-muted-foreground hover:bg-sidebar-accent/50 data-[state=open]:hover:bg-sidebar-accent/50 [&>svg]:size-3.5 [&[data-state=closed]>svg]:rotate-[-90deg] [&>svg]:transition-transform [&>svg]:duration-200"
								>
									<AccordionPrimitive.Trigger>
										<span>{label}</span>
										<ChevronDown className="ml-auto" />
									</AccordionPrimitive.Trigger>
								</SidebarMenuButton>
							</SidebarMenuItem>
						</SidebarMenu>
						<AccordionPrimitive.Content className="data-[state=closed]:animate-accordion-up data-[state=open]:animate-accordion-down mt-1 overflow-hidden">
							{children}
						</AccordionPrimitive.Content>
					</AccordionPrimitive.Item>
				</AccordionPrimitive.Root>
			) : (
				<>
					{label && <SidebarGroupLabel>{label}</SidebarGroupLabel>}
					{children}
				</>
			)}
		</div>
	);
}

